solution_code:
#include <iostream>

int absoluteValue(int n)
{
    if (n < 0)
        return -n;
    else
        return n;
}

int main()
{
    int n {};
    std::cin >> n;
    std::cout << absoluteValue(n) << '\n';
    return 0;
}
